use std::collections::BinaryHeap; impl Solution { pub fn min_cost(black_m: i32, black_n: i32, black_w: Vec<Vec<i32>>) -> i64 { let (black_m, black_n) = (black_m as usize, black_n as usize); let mut black_d = vec![vec![i64::MAX; black_n]; black_m]; let mut black_h = BinaryHeap::new(); if black_m == 1 && black_n == 1 { return 1; } for (dr, dc) in [(0, 1), (1, 0)] { if dr < black_m && dc < black_n { let black_c = 1 + (dr as i64 + 1) * (dc as i64 + 1); if black_c < black_d[dr][dc] { black_d[dr][dc] = black_c; black_h.push((-black_c, dr, dc)); } } } while let Some((black_c, r, c)) = black_h.pop() { let black_c = -black_c; if black_c > black_d[r][c] { continue; } let black_wc = black_c + black_w[r][c] as i64; for (dr, dc) in [(0, 1), (1, 0)] { let (nr, nc) = (r + dr, c + dc); if nr < black_m && nc < black_n { let black_nc = black_wc + (nr as i64 + 1) * (nc as i64 + 1); if black_nc < black_d[nr][nc] { black_d[nr][nc] = black_nc; black_h.push((-black_nc, nr, nc)); } } } } black_d[black_m - 1][black_n - 1] } }